const { MeliStatsD } = require('@meli/statsd');

const { CRON_EVENT_TYPE } = require('../../constants/cron');
const {
  TELEMETRY_CRON_WORKER_SEND_ERROR,
} = require('../../constants/telemetry');
const { logger } = require('../../logger');
const cronStorage = require('../storage');

const statsd = new MeliStatsD();

/**
 * Sets the cron data to the new online worker
 * @param {import('cluster').Worker} worker
 */
async function onNewOnlineWorker(worker) {
  return Promise.all(
    cronStorage.keys().map(async (key) => {
      const value = await cronStorage.get(key);

      worker.send({
        type: CRON_EVENT_TYPE,
        data: {
          key,
          value,
        },
      });
    }),
  ).catch((err) => {
    logger.debug(
      `CronWorkerSendError: failed to send config to worker ${worker.id}, ${err.message}`,
    );

    statsd.increment(TELEMETRY_CRON_WORKER_SEND_ERROR);
  });
}

module.exports = {
  onNewOnlineWorker,
};
